create extension if not exists "pgcrypto";
create type goal_type as enum ('emagrecer','ganhar_massa','condicionamento','vida_saudavel');
create type level_type as enum ('iniciante','intermediario','avancado');
create table profiles(id uuid primary key default gen_random_uuid(), user_id uuid not null unique references auth.users(id) on delete cascade, full_name text not null, age int check(age between 12 and 100), height_cm numeric(5,2) check(height_cm>0), initial_weight_kg numeric(6,2) check(initial_weight_kg>0), current_weight_kg numeric(6,2) check(current_weight_kg>0), goal goal_type not null, level level_type not null, training_frequency int check(training_frequency between 1 and 7), dietary_restrictions text, health_notes text, onboarding_completed boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table user_metrics(id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, measured_at date default current_date, weight_kg numeric(6,2), waist_cm numeric(6,2), chest_cm numeric(6,2), hip_cm numeric(6,2), energy int check(energy between 1 and 5), mood int check(mood between 1 and 5), sleep_quality int check(sleep_quality between 1 and 5), photo_url text, notes text, created_at timestamptz default now());
create table daily_progress(id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, date date not null default current_date, water_liters numeric(4,2) default 0, workout_done boolean default false, meals_ok boolean default false, habit_done boolean default false, completed boolean default false, energy int check(energy between 1 and 5), mood int check(mood between 1 and 5), sleep_quality int check(sleep_quality between 1 and 5), notes text, created_at timestamptz default now(), unique(user_id,date));
create table progress_stages(id int primary key, name text not null, description text not null, motivational_message text not null, unlock_days int not null, required_completed_days int not null, evolution_percent int not null);
create table recipes(id uuid primary key default gen_random_uuid(), name text not null, category text not null, ingredients text[] not null, preparation text not null, prep_time_minutes int not null, calories int not null, protein_g numeric(5,2) not null, healthy_note text not null, image_url text, created_at timestamptz default now());
create table meal_plans(id uuid primary key default gen_random_uuid(), day_number int not null unique check(day_number between 1 and 14), breakfast text not null, morning_snack text not null, lunch text not null, afternoon_snack text not null, dinner text not null, supper text, notes text);
create table workout_plans(id uuid primary key default gen_random_uuid(), week_number int not null, day_label text not null, muscle_groups text not null, intensity text not null, progression_tip text not null);
create table workout_exercises(id uuid primary key default gen_random_uuid(), workout_plan_id uuid references workout_plans(id) on delete cascade, name text not null, sets int not null, reps text not null, rest_seconds int not null, execution text not null, cautions text not null, image_url text);
create table user_workout_logs(id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, workout_plan_id uuid references workout_plans(id), performed_at date default current_date, completed boolean default false, notes text);
create table user_habit_logs(id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, habit_date date default current_date, habit_name text not null, completed boolean default false, notes text);
create index idx_profiles_user_id on profiles(user_id); create index idx_daily_progress_user_date on daily_progress(user_id,date); create index idx_metrics_user_date on user_metrics(user_id,measured_at); create index idx_recipes_category on recipes(category);
create or replace function set_updated_at() returns trigger as $$ begin new.updated_at=now(); return new; end; $$ language plpgsql;
create trigger profiles_updated_at before update on profiles for each row execute function set_updated_at();
alter table profiles enable row level security; alter table user_metrics enable row level security; alter table daily_progress enable row level security; alter table user_workout_logs enable row level security; alter table user_habit_logs enable row level security; alter table recipes enable row level security; alter table meal_plans enable row level security; alter table progress_stages enable row level security; alter table workout_plans enable row level security; alter table workout_exercises enable row level security;
create policy "profiles_select_own" on profiles for select using(auth.uid()=user_id); create policy "profiles_insert_own" on profiles for insert with check(auth.uid()=user_id); create policy "profiles_update_own" on profiles for update using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "metrics_own_all" on user_metrics for all using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "daily_own_all" on daily_progress for all using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "workout_logs_own_all" on user_workout_logs for all using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "habit_logs_own_all" on user_habit_logs for all using(auth.uid()=user_id) with check(auth.uid()=user_id);
create policy "public_recipes_read" on recipes for select using(true); create policy "public_meal_read" on meal_plans for select using(true); create policy "public_stages_read" on progress_stages for select using(true); create policy "public_workouts_read" on workout_plans for select using(true); create policy "public_exercises_read" on workout_exercises for select using(true);
